```class Solution {
public:
    bool isSubstringPresent(string s) {
        int n = s.length();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (s.substr(i, 2) == s.substr(j, 2)) {
                    return true;
                }
            }
        }
        return false;
    }
};
```

